import { forwardRef, useRef } from 'react';
import { useTooltip, type TooltipProp } from '../../hooks/useTooltip';

export interface ArvoIconButtonLinkProps extends Omit<React.AnchorHTMLAttributes<HTMLAnchorElement>, 'href'> {
  variant?: 'primary' | 'secondary' | 'tertiary' | 'outline' | 'danger';
  size?: 'xs' | 'sm' | 'md' | 'lg';
  icon: string;
  href: string;
  tooltip: TooltipProp;
  isDisabled?: boolean;
  isLoading?: boolean;
}

const ArvoIconButtonLink = forwardRef<HTMLAnchorElement, ArvoIconButtonLinkProps>(
  function ArvoIconButtonLink(
    {
      variant = 'primary',
      size = 'md',
      icon,
      href,
      tooltip,
      isDisabled = false,
      isLoading = false,
      target,
      rel,
      className,
      onClick,
      ...rest
    },
    ref
  ) {
    const internalRef = useRef<HTMLAnchorElement | null>(null);
    const tooltipContent = typeof tooltip === 'string' ? tooltip : tooltip.content;

    useTooltip({ triggerRef: internalRef, tooltip });
    const needsRel = target === '_blank';
    const effectiveRel = needsRel
      ? rel ?? 'noopener noreferrer'
      : rel;

    const classes = [
      'arvo-icon-btn',
      `arvo-btn--${variant}`,
      `arvo-btn--${size}`,
      isDisabled ? 'is-disabled' : '',
      isLoading ? 'loading' : '',
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    const blocked = isDisabled || isLoading;

    const handleClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
      if (blocked) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }
      onClick?.(e);
    };

    const mergeRefs = (node: HTMLAnchorElement | null) => {
      internalRef.current = node;
      if (typeof ref === 'function') ref(node);
      else if (ref) ref.current = node;
    };

    return (
      <a
        ref={mergeRefs}
        href={isDisabled ? undefined : href}
        target={isDisabled ? undefined : target}
        rel={isDisabled ? undefined : effectiveRel}
        className={classes}
        aria-label={tooltipContent}
        aria-disabled={isDisabled ? true : undefined}
        aria-busy={isLoading ? true : undefined}
        tabIndex={isDisabled ? 0 : undefined}
        onClick={handleClick}
        {...rest}
      >
        <span
          className={`arvo-btn__ico o9con o9con-${icon}`}
          aria-hidden="true"
        />
      </a>
    );
  }
);

export default ArvoIconButtonLink;
